1. <?php
2. // Simple seeder runner: runs all .sql files in database/seeders in order
3. $base = __DIR__ . '/../database';
4. $configFile = __DIR__ . '/../config.cfg.php';
5. function parseConfig($file) {
6.     $contents = file($file);
7.     $cfg = [];
8.     foreach ($contents as $line) {
9.         $line = trim($line);
10.         if ($line === '' || $line[0] === '#') continue;
11.         if (strpos($line, '<?php') === 0) continue;
12.         if (preg_match('/^([A-Z0-9_]+)\s*=\s*(.*)$/', $line, $m)) {
13.             $key = $m[1];
14.             $val = trim($m[2]);
15.             $cfg[$key] = $val;
16.         }
17.     }
18.     return $cfg;
19. }
20. $cfg = parseConfig($configFile);
21. $host = $cfg['DB_HOST'] ?? '127.0.0.1';
22. $port = isset($cfg['DB_PORT']) ? (int)$cfg['DB_PORT'] : 3306;
23. $user = $cfg['DB_USERNAME'] ?? 'root';
24. $pass = $cfg['DB_PASSWORD'] ?? '';
25. $dbname = $cfg['DB_NAME'] ?? null;
26. if (!$dbname) { fwrite(STDERR, "DB_NAME missing in config.cfg.php\n"); exit(2); }
27. $mysqli = new mysqli($host, $user, $pass, $dbname, $port);
28. if ($mysqli->connect_errno) {
29.     fwrite(STDERR, "Connect failed: " . $mysqli->connect_error . "\n");
30.     exit(2);
31. }
32. $seedDir = realpath(__DIR__ . '/../database/seeders');
33. if (!is_dir($seedDir)) { fwrite(STDERR, "No seeders directory found at $seedDir\n"); exit(1); }
34. $files = glob($seedDir . '/*.sql');
35. sort($files);
36. foreach ($files as $file) {
37.     echo "Running seeder: $file\n";
38.     $sql = file_get_contents($file);
39.     if ($sql === false) { echo "  cannot read\n"; continue; }
40.     if (!$mysqli->multi_query($sql)) {
41.         echo "  Error: " . $mysqli->error . "\n";
42.         break;
43.     }
44.     // consume all results
45.     do {
46.         if ($res = $mysqli->store_result()) { $res->free(); }
47.     } while ($mysqli->more_results() && $mysqli->next_result());
48.     echo "  OK\n";
